import numpy as np

def compute_syndrome(H: np.ndarray, error: np.ndarray) -> np.ndarray:
    return (H @ error) % 2

def verify_syndrome(H: np.ndarray, syndrome: np.ndarray, error: np.ndarray) -> bool:
    return np.array_equal(compute_syndrome(H, error), syndrome)

