import numpy as np
from math import comb, log2

class CombinatorialEncoder:
    def __init__(self, n: int, t: int):
        self.n = n
        self.t = t

    def capacity_bits(self) -> int:
        return int(log2(comb(self.n, self.t)))

    def encode(self, message_int: int) -> np.ndarray:
        positions = []
        remaining = message_int
        for i in range(self.t - 1, -1, -1):
            for n_p in range(self.n - 1, i, -1):
                c = comb(n_p, i + 1)
                if c <= remaining:
                    positions.append(n_p)
                    remaining -= c
                    break
        error = np.zeros(self.n, dtype=int)
        for p in positions:
            error[p] = 1
        while np.sum(error) < self.t:
            for i in range(self.n):
                if error[i] == 0:
                    error[i] = 1
                    break
        return error

    def decode(self, error: np.ndarray) -> int:
        positions = sorted(np.where(error == 1)[0], reverse=True)
        return sum(comb(p, i + 1) for i, p in enumerate(positions))

