import numpy as np
from typing import Optional
from itertools import combinations

class Niederreiter:
    def __init__(self, H_public: np.ndarray, H_secret: np.ndarray, S: np.ndarray, P: np.ndarray, t: int):
        self.H_public = H_public
        self.H_secret = H_secret
        self.S = S
        self.P = P
        self.t = t
        self.r, self.n = H_public.shape
        self.perm = np.argmax(P, axis=1)

    def _invert(self, M):
        n = M.shape[0]
        aug = np.hstack([M, np.eye(n, dtype=int)]) % 2
        for col in range(n):
            for row in range(col, n):
                if aug[row, col] == 1:
                    aug[[col, row]] = aug[[row, col]]
                    break
            for row in range(n):
                if row != col and aug[row, col] == 1:
                    aug[row] = (aug[row] + aug[col]) % 2
        return aug[:, n:]

    def encrypt(self, error: np.ndarray) -> np.ndarray:
        return (self.H_public @ error) % 2

    def decrypt(self, syndrome: np.ndarray) -> Optional[np.ndarray]:
        S_inv = self._invert(self.S)
        s_prime = (S_inv @ syndrome) % 2
        for pos in combinations(range(self.n), self.t):
            e = np.zeros(self.n, dtype=int)
            for p in pos:
                e[p] = 1
            if np.array_equal((self.H_secret @ e) % 2, s_prime):
                result = np.zeros(self.n, dtype=int)
                for i, p in enumerate(self.perm):
                    result[p] = e[i]
                return result
        return None
